// components/EmployerNavbar.jsx
import React, { useState } from 'react';
import { NavLink, Link, useNavigate } from 'react-router-dom';
import './EmployerNavbar.css';

export default function EmployerNavbar({ employer, logout }) {
  const [dropOpen, setDropOpen] = useState(false);
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const NAV_LINKS = [
    { to: '/employer',             label: 'Dashboard',   icon: '▦' },
    { to: '/employer/internships', label: 'Internships', icon: '📋' },
    { to: '/employer/applicants',  label: 'Applicants',  icon: '👥' },
    { to: '/employer/trainings',   label: 'Trainings',   icon: '🎓' },
  ];

  return (
    <nav className="emp-nav">
      <div className="emp-nav__inner">
        {/* Logo */}
        <Link to="/employer" className="emp-nav__logo">
          <span className="emp-nav__logo-icon">◈</span>
          <span className="emp-nav__logo-text">
            Launch<span className="emp-nav__logo-accent">pad</span>
          </span>
          <span className="emp-nav__logo-badge">Employer</span>
        </Link>

        {/* Nav Links */}
        <div className="emp-nav__links">
          {NAV_LINKS.map(({ to, label, icon }) => (
            <NavLink
              key={to}
              to={to}
              end={to === '/employer'}
              className={({ isActive }) =>
                `emp-nav__link ${isActive ? 'emp-nav__link--active' : ''}`
              }
            >
              <span className="emp-nav__link-icon">{icon}</span>
              {label}
            </NavLink>
          ))}
        </div>

        {/* Right side */}
        <div className="emp-nav__right">
          <Link to="/employer/post-internship" className="btn btn-primary btn-sm">
            + Post Role
          </Link>

          {/* Company avatar dropdown */}
          <div className="emp-nav__avatar-wrap" onClick={() => setDropOpen(!dropOpen)}>
            <div
              className="emp-nav__avatar"
              style={{ '--emp-logo-color': employer?.logoColor || '#C4B5FD' }}
            >
              {employer?.logo || 'CO'}
            </div>
            <span className="emp-nav__company-name">{employer?.name || 'Company'}</span>
            <span className="emp-nav__chevron" style={{ transform: dropOpen ? 'rotate(180deg)' : '' }}>▾</span>

            {dropOpen && (
              <div className="emp-nav__dropdown">
                <Link to="/employer/profile" className="emp-nav__drop-item" onClick={() => setDropOpen(false)}>
                  🏢 Company Profile
                </Link>
                <Link to="/employer/post-internship" className="emp-nav__drop-item" onClick={() => setDropOpen(false)}>
                  + Post Internship
                </Link>
                <Link to="/employer/post-training" className="emp-nav__drop-item" onClick={() => setDropOpen(false)}>
                  + Post Training
                </Link>
                <div className="emp-nav__drop-divider" />
                <button className="emp-nav__drop-item emp-nav__drop-item--danger" onClick={handleLogout}>
                  ⎋ Log Out
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
}
